const get_day_name = (dt) => {
    const language = 'fr-fr';
    const options = {  weekday: 'long' };
    const today = new Date(parseInt(dt.split("-")[0]), parseInt(dt.split("-")[1])-1,parseInt(dt.split("-")[2])).toLocaleString(language, options)
    return today
}



const DateTimeComponent = ({ datetime,center=true,size, timesize, inline}) => {
    const d = new Date(datetime)

    if(datetime) 
    return (
        <div className={`${ center ? "text-center" : ""} ${inline ? "inline" : "block"}`} style={{fontSize:size ? size : "8px"}}>
            <div className={`${inline ? "inline" : "block"}`}>{d.getDate()}-{d.getMonth() + 1}-{d.getFullYear()}</div>
            <div className={`${inline ? "inline" : "block"}`}  style={{fontSize:timesize ? timesize : size ? size : "8px"}}>  {d.getHours()}:{d.getMinutes()}</div>
        </div>
    )
    else return (<></>)
}