import {useState} from 'react'
import DatePicker from 'react-date-picker';
import Select from './utils/Select';
import Input from './utils/Input';
import ProductQttSelector from './ProductQttSelector';
import Button from './utils/Button';
import axios from "axios"

export default function AddTracking({order,set_order}) {
    const [_date, set_date] = useState(new Date());
    const [_code, set_code] = useState("");
    const [_observation, set_observation] = useState("");
    const [_type, set_type] = useState("yalidine");
    const [_products, set_products] = useState(order.items.map(it=>({...it,qtt:0})));

    const add_tracking=()=>{
        // set_order({...order,tracking:[...order.tracking,{
        //     date:_date,
        //     code:_code,
        //     type:_type,
        //     products:_products 
        // }]})
        axios({
            url:`https://app.liliumpharma.com/orders/app/api/${order.id}`,
            method:"post",
            data:{
                ...order,
                tracking:[
                    ...order.tracking,
                    {
                        date:_date,
                        code:_code,
                        type:_type,
                        products:_products,
                        observation:_observation 
                    }
                ]
            }
        })
        .then(res=>{
            set_order({...order,tracking:[...order.tracking,{
                date:_date,
                code:_code,
                type:_type,
                products:_products 
            }]})
        })
        .catch(err=>{
            console.log("une erreur s'est produites veuillez reessayer")
            console.log(err)
        })
    }

  return (
    <div className="flex flex-wrap">
        <div className="border-2 border-gray-500 p-2">
            <DatePicker onChange={set_date} value={_date} calendarIcon={null} locale="fr" clearIcon={null}/>
        </div>
        <div className="border-2 border-gray-500 p-2">
            <Select 
                options={[
                    {name:"yalidine",value:"yalidine"},
                    {name:"livreur",value:"livreur"},
                    {name:"bureau",value:"bureau"},
                    {name:"delegue",value:"delegue"}
                ]}
                onChange={(e)=>set_type(e.target.value)}
            />
        </div>
        <div className="border-2 border-gray-500 p-2">
            <Input 
                    placeholder={"code tracking"} 
                    label={""} 
                    type={"text"} 
                    onKeyUp={e=>set_code(e.target.value)}
                />
        </div>
        <div className="border-2 border-gray-500 p-2">
            <ProductQttSelector 
                order={order}
                products={_products}
                set_products={set_products}
            />
        </div>
        <div className="border-2 border-gray-500 p-2">
            <Input 
                    placeholder={"observation"} 
                    label={""} 
                    type={"text"} 
                    onKeyUp={e=>set_observation(e.target.value)}
                />
                <Button onClick={()=>add_tracking()}>
                ajouter
            </Button>
        </div>

        
    </div>
  )
}
