import { useState, useEffect } from 'react'
import Loader from '../utils/Loader'
import { Close } from "@mui/icons-material"
import Input from '../utils/Input'
import Button from '../utils/Button'
import Checkbox from '../utils/Checkbox'



const axios = require("axios")


const get_day_name = (dt) => {
    var dayName = ['Dim', 'Lun', 'Mar', 'Merc', 'Jeu', 'Ven', 'Sam'];
    var day = dayName[new Date(dt.split("-")[0], dt.split("-")[1], dt.split("-")[2]).getDay()];
    return day
}

export default function ClientList({ plan, commune, set_plan }) {

    const [_is_loading, set_is_loading] = useState(false)
    const [_clients_list, set_clients_list] = useState([])

    const [_search, set_search] = useState("");

    const [_spec, set_spec] = useState("medicale");

    

    useEffect(() => {

         !_is_loading && get_clients_list()

    }, [])



    const add_client = (client) => {

        set_is_loading(true)


        axios({
            method: "post",
            url: "PLANS",
            data: { plan_id: plan.id, client_id: client.id }
        })
            .then(res => {
                set_is_loading(false)
                set_plan(res.data)
            })
            .catch(err => {
                set_is_loading(false)
                alert("une erreur s'est produite veuillez réessayer")
            })
    }

    const delete_client = (client) => {
        console.log("deleting client id ", client)
        if (!_is_loading) {
            set_is_loading(true)
            axios({
                method: "delete",
                url: "PLANS",
                data: { plan_id: plan.id, client_id: client.id }
            })
                .then(res => {
                    set_plan(res.data)
                    set_is_loading(false)
                })
                .catch(err => {
                    set_is_loading(false)
                    alert("une erreur s'est produite veuillez réessayer")
                })

        }
    }


    const get_clients_list = () => {
        set_is_loading(true)

        const axios = require("axios")
        axios.defaults.timeout = 100000;
        axios({
            method: "get",
            url: "CLIENTS_SEARCH",
            params: { plan_id: plan.id, all_by_plan: "1", commune: commune.id,spec:_spec }
        })
            .then(res => {
                console.log(res);
                set_is_loading(false)
                set_clients_list(res.data)
            })
            .catch(err => {
                set_is_loading(false)
                console.log(err)
                // alert("une erreur s'est produite veuillez réessayer")
                setTimeout(()=>get_clients_list(),2000)
                
            })
    }

    return (
        <div className='p-2'>
            <div className='py-2'>
                <div className="flex gap-2">
                    <div  
                        className={`p-2 text-white bg-${_spec!="medicale" ? "gray-500" : "green-600"}`}
                        onClick={(e)=>set_spec("medicale")}> Medicale </div>
                    <div 
                        className={`p-2 text-white bg-${_spec=="medicale" ? "gray-500" : "green-600"}`} 
                        onClick={(e)=>set_spec("commerciale")} > Commerciale </div>
               
                </div>
                <h3 className="font-bold text-l mb-2 ">{commune.commune_name}</h3>
            </div>
            <div className="text-center">
                {_is_loading && <Loader />}
            </div>
            <div className="px-2 my-2">
                <Input
                    placeholder='medecin a trouver'
                    onKeyUp={(e)=>set_search(e.target.value)}
                  />
            </div>

            <div className='w-400 bg-slate-900 px-2 py-1 rounded-md overflow-scroll' style={{height:450,overflow:"scroll"}}>
                {
                    _clients_list.filter(cl=>cl.nom.toLowerCase().includes(_search.toLowerCase())).filter(cl=>
                        _spec=="medicale"  ? 
                            !["Pharmacie", "Grossiste", "SuperGros"].includes(cl.specialite)
                             :  
                             ["Pharmacie", "Grossiste", "SuperGros"].includes(cl.specialite) 
                        ).map(client =>
                        <div key={client.id} className='my-3 py-3 flex items-center gap-2' >
                            {
                                plan.clients.filter((e, i) => e.id == client.id).length ?
                                    <Checkbox label={client.nom} on_check={() => delete_client(client)} checked={true} />
                                    :
                                    <Checkbox label={client.nom} on_check={() => add_client(client)} />
                            }
                                <div>
                                    <span className="text-secondary">{client.specialite}</span> <br/>
                                    <small>{client.commercial}</small> 

                                </div>
                                    <small>
                                        <b>{client.last_visite}</b>
                                    </small>

                            
                        </div>
                    )
                }
            </div>
        </div>
    )
}
