import { useState, useEffect, useRef } from 'react'
import Loader from '../utils/Loader'
import { Check, Close, Delete } from "@mui/icons-material"
import ScreenRotationAltIcon from '@mui/icons-material/ScreenRotationAlt';
import Input from '../utils/Input'
import Button from '../utils/Button'
import Hint from '../indications/hint'




const axios = require("axios")
const get_day_name = (dt) => {
    var dayName = ['Dim', 'Lun', 'Mar', 'Merc', 'Jeu', 'Ven', 'Sam'];
    var day = dayName[new Date(dt.split("-")[0], dt.split("-")[1], dt.split("-")[2]).getDay()];
    return day
}



const TaskComponent = ({ task, permuting, on_permute, on_remove, set_plan, plan }) => {

    const [_is_loading, set_is_loading] = useState(false)

    const validate=()=>{
        const axios=require("axios")
        set_is_loading(true);
        axios({
          url:"TASKS",
          params:{task:task.id},
        })
        .then(res=>{
          console.log(res.data)
          set_plan({...plan,tasks:plan.tasks.map(tas=>tas.id == task.id ? res.data : tas )})
          set_is_loading(false)
          
        })
        .catch(err=>{
          console.log(err)
          set_is_loading(false)
        })
    }

    return (
        <>
            <div className={`gap-2 flex items-center justify-between ${ !task.completed && "bg-slate-800"} rounded-md p-2 py-3 my-3 ` + (permuting && permuting == task.id && 'bg-blue-900')}>

                <div  className="grow" onClick={() => on_permute(task.id)}>

                    <div className='bg-green-600 h-7 w-7 text-center font-bold rounded-full mr-3 inline-flex items-center justify-center'>
                        {task.order}
                    </div>
                    {task.task}
                </div>
                {
                        _is_loading ? 
                        <>
                        <Loader />
                        </>
                        :
                        <>
                            {!permuting ?
                                <div className='p-1' onClick={() => { on_remove(task.id) }}>
                                    <Delete sx={{ fill: "#fff" }} />
                                </div>
                                :
                                <ScreenRotationAltIcon />
                            }
                                <Check  sx={{fill: task.completed  ? "#2da231" : "#fff"}} onClick={()=>validate()} />
                        </>
                }
                    
            </div>
        </>
    )
}

export default function TaskForm({ plan, set_plan }) {


    const [_permuting, set_permuting] = useState(null)
    const [_task_description, set_task_description] = useState('')
    const [_is_loading, set_is_loading] = useState(false)
    const [_task_list, set_task_list] = useState(plan.tasks)


    const description_input= useRef(null)



    const clear_input=()=>{
        // console.log([...description_input.current.children])
        [...description_input.current.children].map(child=>{
            console.log(child.className.split(" ").includes("input"))
            if(child.className.split(" ").includes("input"))
                child.value=""   
        })
    }
    const permute_task = (task1, task2) => {

        set_is_loading(true)

        axios({
            method: "post",
            url: "TASK_PERMUTE",
            data: { tasks: [task1, task2] }
        })
            .then(res => {
                set_is_loading(false)
                set_permuting(false)
                console.log(res.data);
                set_plan(res.data)
                description_input.current.val=""
            })
            .catch(err => {
                set_is_loading(false)
                alert("une erreur s'est produite veuillez réessayer")
            })
    }

    const add_task = (task) => {

        if(_task_description!="")
        {
            set_is_loading(true)
        
    
            axios({
                method: "post",
                url: "PLANS",
                data: { plan_id: plan.id, task: task }
            })
                .then(res => {
                    set_is_loading(false)
                    console.log(res.data);
                    set_plan(res.data)
                    set_task_description('')
                    clear_input()
                })
                .catch(err => {
                    set_is_loading(false)
                    console.log(err)
                    alert("une erreur s'est produite veuillez réessayer")
                })
        }
        
    }



    const delete_task = (task) => {
        console.log("deleting task id ", task.id)
        if (!_is_loading) {
            set_is_loading(true)
            axios({
                method: "delete",
                url: "PLANS",
                data: { plan_id: plan.id, task_id: task.id }
            })
                .then(res => {
                    set_plan(res.data)
                    set_is_loading(false)
                })
                .catch(err => {
                    set_is_loading(false)
                    alert("une erreur s'est produite veuillez réessayer")
                })

        }
    }


    const permute = (id_task) => {
        if (_permuting && _permuting == id_task)
            set_permuting(null)
        else if (_permuting) {
            permute_task(_permuting, id_task)
        } else
            set_permuting(id_task)
    }

    return (
        <>
            <div className="px-4 bg-slate-900 text-white py-3 ">
                <div className="bg-slate-700 p-4">

                    {/* <h3 className="font-bold text-l mr-3 inline-block"> {get_day_name(plan.day)} {plan.day}</h3> */}


                    <h3 className="font-bold text-l my-2 inline-block">Liste des Tâches</h3>
                    {_is_loading && <Loader />}


                    <div className="my-4 flex flex-row items-center"  ref={description_input}>
                        <Input
                            placeholder='Entrez votre tâche'
                            onKeyUp={(e) => { set_task_description(e.target.value) }}
                            onBlur={() => setTimeout(() => set_task_list([]), 500)}
                           
                        />
                        <div className='bg-secondary p-2 px-4 rounded-md ml-3' onClick={() => add_task({ "task": _task_description })}>
                            Ajouter
                        </div>
                    </div>
                    <div style={{maxHeight:"450px",overflow:"scroll"}}>
                        {
                            plan.tasks.map(task => (

                                <TaskComponent key={task.id} 
                                    task={task} 
                                    on_remove={() => { delete_task(task) }} 
                                    permuting={_permuting} 
                                    on_permute={permute} 
                                    set_plan={set_plan} 
                                    plan={plan}
                                    />

                            ))
                        }
                    </div>


                    <Hint title="Indication" message="Vous pouvez à tout moment changer l'ordre de vos tâches en appuyant sur le numéro vert associé, puis, sur numéro de la tâche à permuter." />
                </div>
            </div>
        </>
    )
}


