import { useState, useEffect } from 'react'
import Loader from '../utils/Loader'
import { Close } from "@mui/icons-material"
import Input from '../utils/Input'
import Button from '../utils/Button'



const axios = require("axios")
const get_day_name = (dt) => {
    var dayName = ['Dim', 'Lun', 'Mar', 'Merc', 'Jeu', 'Ven', 'Sam'];
    var day = dayName[new Date(dt.split("-")[0], dt.split("-")[1], dt.split("-")[2]).getDay()];
    return day
}

export default function ClientForm({ plan, set_plan, show_medecin_in_commune_list }) {



    const [_name, set_name] = useState("")
    const [_is_loading, set_is_loading] = useState(false)
    const [_clients_list, set_clients_list] = useState([])


    useEffect(() => {

        _name.length > 2 && get_clients_list()

        return () => {

        }
    }, [_name])


    const get_clients_list = () => {
        set_is_loading(true)

        const axios = require("axios")
        axios({
            method: "get",
            url: "CLIENTS_SEARCH",
            params: { plan_id: plan.id, medecin: _name, search: "1" }
        })
            .then(res => {
                set_is_loading(false)
                set_clients_list(res.data)
            })
            .catch(err => {
                set_is_loading(false)
                console.log(err)
                alert("une erreur s'est produite veuillez réessayer")
            })
    }



    const add_client = (client) => {

        set_is_loading(true)


        axios({
            method: "post",
            url: "PLANS",
            data: { plan_id: plan.id, client_id: client.id }
        })
            .then(res => {
                set_is_loading(false)
                set_plan(res.data)
            })
            .catch(err => {
                set_is_loading(false)
                alert("une erreur s'est produite veuillez réessayer")
            })
    }



    const delete_client = (client) => {
        console.log("deleting client id ", client)
        if (!_is_loading) {
            set_is_loading(true)
            axios({
                method: "delete",
                url: "PLANS",
                data: { plan_id: plan.id, client_id: client.id }
            })
                .then(res => {
                    set_plan(res.data)
                    set_is_loading(false)
                })
                .catch(err => {
                    set_is_loading(false)
                    alert("une erreur s'est produite veuillez réessayer")
                })

        }
    }


    return (
        <>
            <div className="px-4 bg-slate-900 text-white py-3 ">
                <div className="bg-slate-700 p-4">
                    <h3 className="font-bold text-l text-center"> {get_day_name(plan.day)} {plan.day}</h3>

                    <h3 className="font-bold text-sm text-gray-300 my-3">Régions à visiter</h3>

                    <div className='flex gap-2 my-2'>
                        {
                            plan.communes.map(commune => (
                                <div className='flex flex-col rounded text-md bg-slate-900' key={commune.id} onClick={() => show_medecin_in_commune_list(commune)}>
                                    <span className="p-1">{commune.nom}</span>
                                    <div className="bg-slate-800 text-[12px] rounded-br rounded-bl p-1">
                                        <span><span className="text-primary">{commune.client_count}</span> / {commune.client_all_count}  {(commune.client_count <= 1 ? "Médecin" : "Médecins")}</span>
                                    </div>
                                    <div className="bg-slate-800 text-[12px] rounded-br rounded-bl p-1">
                                        <span> <span className="text-primary">{commune.commercial_count}</span> / {commune.commercial_all_count} {(commune.commercial_count <= 1 ? "Commercial" : "Commerciaux")}</span>
                                    </div>
                                </div>
                            ))
                        }
                    </div>

                    <h3 className="font-bold text-sm text-gray-300 my-3">Liste à visiter</h3>
                    <div className="text-center">{_is_loading && <Loader />}</div>
                    {
                        plan.clients.map(client => (
                            <span key={client.id} className="inline-block p-1 mx-2 bg-secondary font-bold text-white rounded text-xs">
                                {client.nom}
                                <Close sx={{ fill: "#fff" }} onClick={() => { delete_client(client) }} fontSize="10px" />
                            </span>
                        ))
                    }
                    <div className="my-4">
                        <Input
                            placeholder='Entrez le nom du client'
                            onKeyUp={(e) => { set_name(e.target.value) }}
                            onBlur={() => setTimeout(() => set_clients_list([]), 500)}
                        />
                    </div>
                </div>
                <div style={{ height: "200px", overflow: "scroll" }}>
                    {
                        _clients_list.map(client =>
                            <div key={client.id} className='py-3 flex items-center gap-2' onClick={(e) => { add_client(client) }}>
                                <div>
                                    <div className="inline-block bg-secondary w-[10px] h-[10px] rounded-full mr-3"></div>
                                    <span className="text-secondary">{client.wilaya_name}</span>
                                </div>
                                {client.nom}
                            </div>
                        )
                    }
                </div>
                {/* <div className="my-3">
                <Button loading={_is_loading} onClick={()=>set_show_form(false)} >
                    Valider
                </Button>
            </div> */}
            </div>
        </>
    )
}
